import { ResearchUpdate, Article, Topic } from "../types";
import { calculateBaseClinicalScore } from "../constants/searchConstants";
import { getEPMCTopicQuery } from "../utils/searchContexts";
import { detectArticleCategory } from "../utils/categoryDetection";

const EPMC_API_BASE = 'https://www.ebi.ac.uk/europepmc/webservices/rest/search';

const fetchWithProxyFallback = async (url: string): Promise<any> => {
    // Strategy: Try direct, then various public proxies in order of reliability
    const proxies = [
        (u: string) => u, // Direct fetch (works if CORS is configured or in native context)
        (u: string) => `https://corsproxy.io/?${encodeURIComponent(u)}`,
        (u: string) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}`,
        (u: string) => `https://api.codetabs.com/v1/proxy?quest=${encodeURIComponent(u)}`
    ];

    let lastError: any;

    for (const proxyGen of proxies) {
        try {
            const proxyUrl = proxyGen(url);
            const response = await fetch(proxyUrl, {
                headers: {
                    'Accept': 'application/json'
                }
            });

            if (response.ok) {
                const text = await response.text();
                // Validate that we actually got JSON and not an HTML error page from a proxy
                try {
                    const json = JSON.parse(text);
                    return json;
                } catch (parseError) {
                    // console.warn(`JSON parse failed for ${proxyUrl}`, parseError);
                    lastError = parseError;
                    // Continue to next proxy
                }
            } else {
                 lastError = new Error(`HTTP ${response.status} from ${proxyUrl}`);
            }
        } catch (e) {
            // console.warn(`Fetch failed for proxy strategy`, e);
            lastError = e;
        }
    }

    throw lastError || new Error("Europe PMC unreachable via all channels.");
};

export const fetchEuropePmcArticles = async (
  topic: Topic | string,
  language: 'es' | 'original' = 'original',
  customQuery?: string
): Promise<ResearchUpdate> => {
  try {
    const mainTerm = customQuery || getEPMCTopicQuery(topic);
    // Use encoded quotes to ensure stability across proxies
    const query = customQuery ? `${mainTerm}` : `(${mainTerm}) AND (HAS_ABSTRACT:y) AND (PUB_YEAR:[2024 TO 2026])`;

    const params = new URLSearchParams({
        query: query,
        format: 'json',
        pageSize: '40',
        resultType: 'core',
        sort: 'DATE_DESC'
    });

    const url = `${EPMC_API_BASE}?${params.toString()}`;
    const data = await fetchWithProxyFallback(url);
    const resultList = data.resultList?.result || [];

    if (resultList.length === 0) return { summary: "No results found in Europe PMC.", articles: [] };

    const articles: Article[] = resultList.map((item: any) => {
      const title = item.title || 'Untitled';
      const abstractText = item.abstractText || "";
      const cleanAbstract = abstractText.replace(/<[^>]*>?/gm, '');
      const source = item.journalTitle || 'Europe PMC';
      const date = item.firstPublicationDate || item.pubYear || 'N/A';
      const year = parseInt(item.pubYear, 10) || 0;

      const relevance = calculateBaseClinicalScore(title, cleanAbstract, source, typeof topic === 'string' ? topic : '', 0, year);
      const category = detectArticleCategory(title, cleanAbstract, source);

      let authorsStr = "";
      if (item.authorList && item.authorList.author) {
          const authors = item.authorList.author;
          const names = authors.slice(0, 3).map((a: any) => a.lastName || a.fullName);
          if (authors.length > 3) names.push("et al");
          authorsStr = names.join(", ");
      }

      const isFree = item.isOpenAccess === 'Y' || item.epmcAuthMan === 'Y';
      // Prioritize full text links
      const link = item.fullTextUrlList?.fullTextUrl?.find((u: any) => u.documentStyle === 'html' || u.documentStyle === 'pdf')?.url || `https://europepmc.org/article/MED/${item.pmid}`;

      return {
        id: `epmc-${item.id}`,
        title: title,
        summary: cleanAbstract || "Abstract not available.",
        source: source,
        authors: authorsStr,
        url: link,
        date: date,
        category: category,
        relevanceScore: relevance,
        topic: typeof topic === 'string' ? topic : 'General',
        isFree: isFree
      };
    });

    return {
      summary: `Europe PMC: ${articles.length} results.`,
      articles: articles
    };
  } catch (error) {
    console.warn("Europe PMC Service Error:", error);
    return { summary: "Error fetching Europe PMC", articles: [] };
  }
};

import { Article } from "../types";

/**
 * Detecta la categoría de un artículo basándose en patrones semánticos del título y abstract.
 */
export const detectArticleCategory = (title: string, summary: string, source: string = ""): Article['category'] => {
  const text = (title + " " + summary).toLowerCase();
  const sourceLower = source.toLowerCase();

  // 1. Detección de ENSAYOS CLÍNICOS (Prioridad Máxima)
  const isTrial = 
    /\bnct\d{8}\b/i.test(text) || // Registro NCT
    /\b(randomized|randomised|aleatorizado)\b/.test(text) ||
    /\b(double-blind|doble ciego|placebo-controlled)\b/.test(text) ||
    /\b(clinical trial|ensayo clínico)\b/.test(text) ||
    /\bphase [1-4] (trial|study)\b/.test(text) ||
    sourceLower.includes("clinicaltrials.gov");

  if (isTrial) return 'Clinical Trial';

  // 2. Detección de REPORTES DE CASO (Case Study)
  // Buscamos patrones típicos de presentación de casos
  const isCaseStudy = 
    /\b(case report|reporte de caso|case series|serie de casos)\b/.test(text) ||
    /\b(a \d+-year-old (man|woman|male|female|patient|boy|girl))\b/.test(text) ||
    /\b(una? paciente de \d+ años)\b/.test(text) ||
    /^case report:/.test(title.toLowerCase()) ||
    /\bunusual presentation of\b/.test(text);

  if (isCaseStudy) return 'Case Study';

  // 3. Detección de INVESTIGACIÓN PRIMARIA / REVISIONES (Research)
  // Si tiene un score de relevancia alto o palabras clave de investigación sólida
  const isResearch = 
    /\b(meta-analysis|metaanálisis|systematic review|revisión sistemática)\b/.test(text) ||
    /\b(prospective|retrospective|cohort|observational)\b/.test(text) ||
    /\b(cross-sectional|estudio transversal)\b/.test(text) ||
    /\b(pilot study|estudio piloto)\b/.test(text);

  if (isResearch) return 'Research';

  // 4. Detección de NOTICIAS / EDITORIALES (News)
  const isNews = 
    sourceLower.includes("news") || 
    sourceLower.includes("reuters") ||
    sourceLower.includes("medscape") ||
    /\b(breaking news|update on|editorial|commentary|perspective)\b/.test(title.toLowerCase());

  if (isNews) return 'News';

  // 5. Fallback: Si parece académico pero no encaja en lo anterior
  return 'Publication';
};

export type StudyDesign = 'RCT' | 'Meta-Analysis' | 'Guideline' | 'Cohort' | 'Review' | 'Case Report' | 'Basic Science' | 'Other';

export const detectStudyDesign = (article: { title: string; summary: string; source?: string; category?: string }): StudyDesign => {
  const text = (article.title + " " + article.summary).toLowerCase();
  const source = (article.source || "").toLowerCase();

  // 1. Guidelines (Highest Priority)
  if (/\b(kdigo|guideline|consensus|practice param|position statement|recommendation)\b/.test(text) || article.category === 'Manual') {
      return 'Guideline';
  }

  // 2. Meta-Analysis / Sys Review
  if (/\b(meta-analysis|systematic review|metaanálisis|revisión sistemática)\b/.test(text)) {
      return 'Meta-Analysis';
  }

  // 3. RCTs
  if (
      /\b(randomized|randomised|aleatorizado|rct|double-blind|doble ciego|placebo-controlled)\b/.test(text) || 
      article.category === 'Clinical Trial' ||
      source.includes('clinicaltrials.gov')
  ) {
      return 'RCT';
  }

  // 4. Cohort / Observational
  if (/\b(cohort|prospective|retrospective|observational|longitudinal|registry|cross-sectional|transversal)\b/.test(text)) {
      return 'Cohort';
  }

  // 5. Case Reports
  if (/\b(case report|case series|reporte de caso|serie de casos)\b/.test(text) || article.category === 'Case Study') {
      return 'Case Report';
  }

  // 6. Basic Science / Murine
  if (/\b(mice|mouse|rat|rats|murine|in vitro|cell line|zebrafish)\b/.test(text) && !/\b(human|patient|clinical)\b/.test(text)) {
      return 'Basic Science';
  }

  // 7. Reviews (Narrative)
  if (/\b(review|overview|update on|current concepts|review article)\b/.test(text) || /\breview\b/i.test(article.title)) {
      return 'Review';
  }

  return 'Other';
};

