          if (existingIndex !== -1) {
              const next = [...prev];
              next[existingIndex] = { ...next[existingIndex], note };
              return next;
          } else if (note.trim().length > 0) {
              const sourceArticle = articles.find(a => a.id === articleId);
              if (sourceArticle) return [{ ...sourceArticle, note }, ...prev];
          }
          return prev;
      });
