const ArticleCard: React.FC<ArticleCardProps> = ({ article, isSaved, onToggleSave, language = 'es', textSize = 'base', isDarkMode = false, groqApiKey, geminiApiKey, onReadFullText, onExpandStateChange, onUpdateNote, onUpdateVisualAbstract, defaultXrayMode, isSelectionMode, isSelected, onSelect, isDownloaded, onReadOffline, onOpenImmersive, isCompact = false, onUpdateArticle }) => {
  const [showRelated, setShowRelated] = useState(false);
  const [loadingRelated, setLoadingRelated] = useState(false);
  const [relatedArticles, setRelatedArticles] = useState<Article[]>([]);
  const [isExpanded, setIsExpanded] = useState(false);
  const [enhancedData, setEnhancedData] = useState<{ summary: string; tldr: { change: string; population: string } } | null>(null);
  const [isEnhancing, setIsEnhancing] = useState(false);
  const [isGeneratingVisual, setIsGeneratingVisual] = useState(false);
  const [viewMode, setViewMode] = useState<'original' | 'enhanced'>('original');
  const [isXrayMode, setIsXrayMode] = useState(defaultXrayMode || false);
  const [showNoteEditor, setShowNoteEditor] = useState(false);
  const [imageError, setImageError] = useState(false);

  // Citation Menu State
  const [showCiteMenu, setShowCiteMenu] = useState(false);

  const cardRef = useRef<HTMLDivElement>(null);
  const textContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setIsXrayMode(defaultXrayMode || false); }, [defaultXrayMode]);

  const uiLang = language === 'es' ? 'es' : 'en';
  const t = translations[uiLang];
  const highlights = article.highlights || [];

  const doiMatch = article.url?.match(/10\.\d{4,9}\/[-._;()/:A-Z0-9a-zA-Z]+/i);
  const doi = doiMatch ? doiMatch[0] : null;

  const wordCount = article.summary.split(/\s+/).length;
  const readTime = Math.max(1, Math.ceil(wordCount / 200));

  const handleToggleExpand = () => {
    if (isSelectionMode && onSelect) { onSelect(article); return; }
    if (isCompact) { if (onOpenImmersive) onOpenImmersive(article); return; }
    if (!isExpanded && navigator.vibrate) navigator.vibrate(10);
    const newState = !isExpanded;
    setIsExpanded(newState);
    if (onExpandStateChange) onExpandStateChange(newState);
  };

  const handleEnhance = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!groqApiKey || isEnhancing) return;
    setIsEnhancing(true);
    try {
        const result = await enhanceArticleSummary(article.title, article.summary, language as Language, groqApiKey);
        if (result) {
            setEnhancedData(result);
            setViewMode('enhanced');
            if (onUpdateArticle) {
                onUpdateArticle(article.id, { 
                  summary: result.summary, 
                  clinicalTldr: result.tldr 
                });
            }
        }
    } catch (err) {
        console.error("Enhancement failed", err);
    } finally {
        setIsEnhancing(false);
    }
  };

  const handleGenerateVisual = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isGeneratingVisual || article.visualAbstract) {
        if (!isExpanded) setIsExpanded(true);
        return;
    }
    setIsGeneratingVisual(true);
    try {
        const result = await generateGeminiVisual(article.title, article.summary, language as Language, geminiApiKey);
        if (result && onUpdateVisualAbstract) {
            onUpdateVisualAbstract(article.id, result);
            setIsExpanded(true);
        }
    } catch (err) {
        console.error("Visual generation failed", err);
    } finally {
        setIsGeneratingVisual(false);
    }
  };

  const handleShare = async () => {
    if (navigator.share) {
      try { await navigator.share({ title: article.title, text: article.summary, url: article.url }); } catch (e) {}
    } else {
      navigator.clipboard.writeText(article.url);
      alert(t.shareCopied);
    }
  };

  // --- Citation Logic ---
  const getAuthors = () => article.authors || "Unknown Authors";
  const getYear = () => article.date ? (article.date.match(/\d{4}/) ? article.date.match(/\d{4}/)?.[0] : "n.d.") : "n.d.";

  const handleCopyCitation = (format: 'AMA' | 'APA' | 'Vancouver') => {
      let citation = '';
      const authors = getAuthors();
      const title = article.title.replace(/\.$/, ''); // Remove trailing dot if exists
      const source = article.source || 'Journal';
      const year = getYear();
      const date = article.date;
      const url = article.url;

      switch (format) {
          case 'AMA':
              // Author(s). Title. Journal. Year;Date. URL
              citation = `${authors}. ${title}. ${source}. ${date}. ${url}`;
              break;
          case 'APA':
              // Author(s). (Year). Title. Source. URL
              citation = `${authors}. (${year}). ${title}. ${source}. ${url}`;
              break;
          case 'Vancouver':
              // Author(s). Title. Source. Date; Issue. Available from: URL
              citation = `${authors}. ${title}. ${source}. ${date}. Available from: ${url}`;
              break;
      }

      navigator.clipboard.writeText(citation);
      // Small feedback using vibration or simple alert for now
      if (navigator.vibrate) navigator.vibrate(50);
      alert(`${t.copied}: ${format}`);
      setShowCiteMenu(false);
  };

  const handleCiteClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    setShowCiteMenu(!showCiteMenu);
  };

  const handleEvidenceFlow = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onReadFullText) onReadFullText(article);
  };

  const handleTitleClick = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (onOpenImmersive) {
          onOpenImmersive(article);
      } else {
          handleEvidenceFlow(e);
      }
  };

  const handleToggleNote = (e: React.MouseEvent) => {
      e.stopPropagation();
      if (isCompact) { if (onOpenImmersive) onOpenImmersive(article); return; }
      if (!isExpanded) setIsExpanded(true);
      setShowNoteEditor(!showNoteEditor);
  };

