    const ai = getAIClient(apiKey);
    const prompt = `Refine and translate PICO terms for PubMed search into highly specific English medical terms: P:"${p}" I:"${i}" C:"${c}" O:"${o}". Return JSON.`;
    try {
        const response = await fetchWithRetry<GenerateContentResponse>(() => ai.models.generateContent({
