            setCoreApiKey(p.coreApiKey || ''); setS2ApiKey(p.s2ApiKey || '');
            setAutoXray(p.autoXray !== undefined ? p.autoXray : true);
            setShowNewsFeed(p.showNewsFeed !== undefined ? p.showNewsFeed : true);
