       <AnimatePresence>{activeImmersiveArticle && <ImmersiveReader article={activeImmersiveArticle} onClose={() => setActiveImmersiveArticle(null)} isDarkMode={isDarkMode} onUpdateNote={handleUpdateNote} />}</AnimatePresence>
       <OfflineReader isOpen={isReaderOpen} onClose={() => setIsReaderOpen(false)} article={readerArticle} htmlContent={readerHtml} isDarkMode={isDarkMode} isLoading={isReaderLoading} onSaveOffline={handleSaveOffline} isAlreadyDownloaded={readerArticle ? !!offlineStatus[readerArticle.id] : false} />
       {viewingHistorySnapshot && <HistoryViewer snapshot={viewingHistorySnapshot} onClose={() => setViewingHistorySnapshot(null)} isDarkMode={isDarkMode} onToggleSave={toggleSave} savedArticles={savedArticles} language={uiLanguage === 'es' ? 'es' : 'original'} textSize={textSize} apiKey={geminiApiKey} groqApiKey={groqApiKey} offlineStatus={offlineStatus} onReadOffline={() => {}} onReadFullText={handleFetchFullText} />}
    </div>
  );
}
